ALTER TABLE llm_model ADD CONSTRAINT ck_llm_model_modality
    CHECK (modality IN ('CHAT','EMBEDDING','RERANK'));
ALTER TABLE llm_model ADD CONSTRAINT ck_llm_model_visibility
    CHECK (visibility IN ('PUBLIC','GRANTED'));
ALTER TABLE llm_model ADD CONSTRAINT ck_llm_model_api_protocol_override
    CHECK (api_protocol_override IS NULL OR api_protocol_override IN
        ('openai-completions','openai-responses','azure-openai-responses','anthropic-messages'));

ALTER TABLE llm_model_price ADD CONSTRAINT ck_llm_model_price_mode
    CHECK (pricing_mode IN ('PRICED','FREE','UNPRICED'));
ALTER TABLE llm_model_price ADD CONSTRAINT ck_llm_model_price_window
    CHECK (effective_to IS NULL OR effective_to > effective_from);
CREATE UNIQUE INDEX ux_llm_model_price_open ON llm_model_price (model_id) WHERE effective_to IS NULL;

ALTER TABLE workspace_llm_model ADD CONSTRAINT ck_ws_llm_model_modality
    CHECK (modality IN ('CHAT','EMBEDDING','RERANK'));
ALTER TABLE workspace_llm_model ADD CONSTRAINT ck_ws_llm_model_pricing_mode
    CHECK (pricing_mode IN ('PRICED','FREE','UNPRICED'));
ALTER TABLE workspace_llm_model ADD CONSTRAINT ck_ws_llm_model_api_protocol_override
    CHECK (api_protocol_override IS NULL OR api_protocol_override IN
        ('openai-completions','openai-responses','azure-openai-responses','anthropic-messages'));

ALTER TABLE instance_llm_settings ADD CONSTRAINT ck_instance_llm_settings_singleton CHECK (id = 1);
ALTER TABLE instance_llm_settings ADD CONSTRAINT ck_instance_llm_settings_policy
    CHECK (default_unpriced_policy IN ('WARN','BLOCK'));
INSERT INTO instance_llm_settings (id, allowed_egress_hosts, allow_workspace_connections, default_unpriced_policy)
    VALUES (1, NULL, TRUE, 'WARN') ON CONFLICT (id) DO NOTHING;

ALTER TABLE llm_usage_event ADD CONSTRAINT ck_llm_usage_event_pricing_state
    CHECK (pricing_state IN ('PRICED','FREE','UNPRICED'));
ALTER TABLE llm_usage_event ADD CONSTRAINT ck_llm_usage_event_funding_source
    CHECK (funding_source IN ('INSTANCE','WORKSPACE'));
-- Classify migrated history conservatively. A positive cost is genuinely PRICED. A zero cost
-- with NO tokens burned is a genuine no-op -> FREE. A zero cost WITH burned tokens is the
-- "runtime didn't price it" trap (see LlmUsageRecorder) and a NULL cost is unknown: both stay
-- UNPRICED (the default) so they surface as unverifiable rather than silently counting as $0.
UPDATE llm_usage_event SET pricing_state = 'PRICED' WHERE cost_usd > 0;
UPDATE llm_usage_event SET pricing_state = 'FREE'
    WHERE cost_usd = 0
      AND (input_tokens + output_tokens + cache_read_tokens + cache_write_tokens) = 0;

ALTER TABLE config_audit_event DROP CONSTRAINT ck_config_audit_event_entity_type;
ALTER TABLE config_audit_event ADD CONSTRAINT ck_config_audit_event_entity_type
    CHECK (entity_type IN (
        'PRACTICE_REVIEW_SETTINGS', 'AI_CONFIG_BINDING', 'AGENT_CONFIG',
        'WORKSPACE_ROLE', 'WORKSPACE_FEATURES', 'WORKSPACE_STATUS',
        'WORKSPACE_TOKEN', 'WORKSPACE_VISIBILITY', 'PRACTICE_ACTIVE',
        'WORKSPACE_LLM_BUDGET', 'WORKSPACE_LLM_CONNECTION', 'WORKSPACE_LLM_MODEL'
    ));

