    ON agent_job (created_at ASC, id)
    WHERE status = 'QUEUED';

CREATE INDEX ix_agent_job_running_config
    ON agent_job (config_id)
    WHERE status = 'RUNNING';

DROP INDEX IF EXISTS ix_agent_job_queued_created;
CREATE INDEX ix_agent_job_queued_available
    ON agent_job (available_at, id)
    WHERE status = 'QUEUED';

